from itertools import product
class Solution:
    def sortableIntegers(self, nums):
        n = len(nums)
        def divisors(m):
            ds = []
            i = 1
            while i * i <= m:
                if m % i == 0:
                    ds.append(i)
                    if i != m // i:
                        ds.append(m // i)
                i += 1
            return ds
        target = sorted(nums)
        total = 0
        for k in divisors(n):
            blocks = [nums[i:i + k] for i in range(0, n, k)]
            options = [[b[r:] + b[:r] for r in range(k)] for b in blocks]
            found = False
            for combo in product(*options):
                merged = []
                for c in combo:
                    merged.extend(c)
                if merged == target:
                    found = True
                    break
            if found:
                total += k
        return total

