                    if i != m // i:
                        ds.append(m // i)
                i += 1
            return ds
        def is_rotation(a, b):
            if len(a) != len(b):
                return False
            if sorted(a) != sorted(b):
                return False
            ea = ',' + ','.join(str(x) for x in a) + ','
            doubled = ea + ea[1:]
            eb = ',' + ','.join(str(x) for x in b) + ','
            return eb in doubled
        target = sorted(nums)
        total = 0
        for k in divisors(n):
            ok = True
            for start in range(0, n, k):
                a = nums[start:start + k]
                b = target[start:start + k]
                if not is_rotation(a, b):
                    ok = False
                    break
            if ok:
                total += k
        return total

