var sortableIntegers = function(nums) {
    const n = nums.length;
    function divisors(m) {
        const ds = [];
        for (let i = 1; i * i <= m; i++) {
            if (m % i === 0) {
                ds.push(i);
                if (i !== m / i) ds.push(m / i);
            }
        }
        return ds;
    }
    function isRotation(a, b) {
        if (a.length !== b.length) return false;
        const sa = a.slice().sort((x, y) => x - y);
        const sb = b.slice().sort((x, y) => x - y);
        for (let i = 0; i < sa.length; i++) if (sa[i] !== sb[i]) return false;
        const ea = ',' + a.join(',') + ',';
        const doubled = ea + ea.slice(1);
        const eb = ',' + b.join(',') + ',';
        return doubled.includes(eb);
    }
    const target = nums.slice().sort((x, y) => x - y);
    let total = 0;
    for (const k of divisors(n)) {
        let ok = true;
        for (let start = 0; start < n; start += k) {
            const a = nums.slice(start, start + k);
            const b = target.slice(start, start + k);
            if (!isRotation(a, b)) { ok = false; break; }
        }
        if (ok) total += k;
    }
    return total;
};
